import { useNavigate } from 'react-router-dom';
import { useState } from 'react';
import '../styles/Home.css';
import Header from '../components/Header';
import Footer from '../components/Footer';
import Input from '../components/Input';

const Home = () => {
    const [poste, setPoste] = useState('');
    const [lieu, setLieu] = useState('');
    const navigate = useNavigate();

    const handleRecherche = () => {
        navigate(`/offers?poste=${encodeURIComponent(poste)}&lieu=${encodeURIComponent(lieu)}`);
    };

    return (
        <div>
            < Header />
            <main>
                <section id="banniere">
                    <p>Votre talent, notre pièce maîtresse</p>
                    <img
                        src="/images/equipe_puzzle.webp"
                        srcSet="/images/equipe_puzzle-400.webp 400w, /images/equipe_puzzle.webp 800w"
                        sizes="100vw"
                        alt="Equipe puzzle"
                        fetchPriority="high"
                        width="800"
                        height="534"
                    />
                </section>
                <section id="recherche">
                    <div>
                        <p>Quel poste recherchez-vous ?</p>
                        <Input placeholder="Saisissez une profession" value={poste} onChange={(e) => setPoste(e.target.value)} />
                    </div>
                    <div>
                        <p>Dans quel lieu ?</p>
                        <Input placeholder="Saisissez un lieu" value={lieu} onChange={(e) => setLieu(e.target.value)} />
                    </div>
                    <button onClick={handleRecherche}>Rechercher</button>
                </section>
                <section id="connexion_inscription">
                    <button>Connexion</button>
                    <button>Inscription</button>
                </section>
            </main>
            <Footer />
        </div>
    );
};

export default Home;